INSERT INTO `faqs` (`id`, `question`, `answer`, `lang`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'نص االسلؤال 2', '<p>الاجابة    2</p>', 'EN', '2016-04-03 20:02:34', '2016-04-03 20:04:43', '2016-04-03 20:04:43'),
(2, 'كيف يمكنني الانضمام إلى الشرق وكلاء التأمين ؟', '<p>تواصل معنا على أحد عناويينا، سيتواصل معك أحد مندوبينا لتقديم الخدمة المناسبة ومساعدتك في اختيار أفضل خيارات التأمين.</p>', 'AR', '2016-04-12 18:03:35', '2016-04-12 18:03:35', NULL),
(3, 'كيف يمكننا ان نساعدك إذا كان لديك بالفعل تغطية تأمينية ؟', '<p class=\"MsoListParagraphCxSpFirst\" dir=\"RTL\" style=\"margin: 0in 1in 0.0001pt 0in;\"><span lang=\"AR-QA\">ان صياغة وثيقة التأمين هى حالة تطور\r\nمستمر وانه من الممكن إدخال التحسينات على الوثيقة والتأكد من سلامة التغطية وقد\r\nتكون هناك أيضا أخطار غير مغطاة وقد لا تدركها تماما ا وان يكون هناك إمكانية\r\nتحقيق وفر في أقساط  التأمين وهذا هو دورنا.</span></p><p class=\"MsoListParagraphCxSpFirst\" dir=\"RTL\" style=\"margin: 0in 1in 0.0001pt 0in;\">اجعلنا وسيط التأمين الخاص بك ونحن\r\nنتولى تقديم وثائقك ومراجعتها لضمان حمايتك.</p>', 'AR', '2016-04-16 06:02:21', '2016-04-16 06:02:21', NULL),
(4, 'لماذا أنتم بحاجة الى وسيط تأمين؟', '<p class=\"MsoListParagraphCxSpFirst\" dir=\"RTL\" style=\"margin: 0in 0.75in 0.0001pt 0in; line-height: 1.4;\"><ul><li><span style=\"line-height: 1.4;\">وثيقة\r\nالتأمين هى وثيقة قانونية معقدة وبها العديد من الشروط والإلتزامات ووسيط التأمين\r\nالمحترف هو أقدر على التعامل مع هذه الوثيقة والتي قد لا يهتم الكثير من قراءتها\r\nوالتعرف عليها والتأكد من كونها تناسب احتياجاتكم.</span><br></li><li><span style=\"line-height: 23px;\">ان\r\nالأفراد والشركات التجارية والهيئات يتعرضون لشتى أنواع المخاطر المادية والمالية،\r\nومهنية وسيط التأمين المحترف سوف تساعدكم على فهم هذه الأمور والمساعدة في التدبير\r\nالتي يمكن اتخاذها للتصدي لهذه الآثار مع خدمات إدارة المخاطر . ومهنية وسيط التأمين\r\nمن شانها ان تساعدكم في الوصول الى أحسن وانسب خدمة تأمينية .</span><br></li><li><span style=\"line-height: 23px;\">اتفق\r\nالمنظمين وشركات التأمين على ان وجود وسيط تأمين يستخدم بوصفه وسيط في التعامل فقط\r\nحيت ان القسط الذي يدفعه العميل اذا لم يكن أقل فأنه يظل كما هو على عكس التعامل\r\nمباشرة مع شركة التأمين . ويمكن القول ان خدمات وسيط التأمين تاتي بدون أي تكلفة\r\nإضافية لكم.</span><br></li><li><span style=\"line-height: 23px;\">في\r\nالسوق العديد من الشركات المتنافسة ونوعية الخدمات والمنتجات في كثير من الأحيان\r\nقد لا تتناسب مع طبيعة الخطر . مهنية وسيط التأمين المحترف سوف تساعدك في الحصول\r\nعلى أفضل ما هو متاح من الخدمة.</span><br></li></ul></p><p>\r\n\r\n\r\n\r\n\r\n\r\n</p>', 'AR', '2016-04-16 06:03:30', '2016-04-16 06:03:30', NULL);
