INSERT INTO `news` (`id`, `title`, `detail`, `category_id`, `image`, `status`, `date`, `lang`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'تعيين 94 كاتب عدل في عدد من المناطق', '<p data-mce-style=\"text-align: justify;\" dir=\"RTL\" style=\"text-align: justify;\">\r\n	<strong><span style=\"font-family:arial,helvetica,sans-serif;\"><span style=\"font-size:16px;\"><span style=\"color:#696969;\">الرياض-أسامةالجمعان:<br />\r\n	عينت وزارة العدل (94) كاتب عدل في عدد من كتابات العدل بمناطق المملكة المختلفة. وأوضح المتحدث الرسمي لوزارة العدل فهد البكران انه تم إنهاء إصدار قرارات تعيين كتاب العدل عقب إجراء الاختبار التحريري والمقابلة الشخصية لجميع المعينين وبعد اجتيازهم جميع الشروط المطلوبة تمت مباشرتهم في مقرات وظائفهم في منطقة الرياض ومنطقة عسير ومنطقة جازان ومنطقة نجران ومنطقة حائل والمنطقة الشرقية ومنطقة الحدود الشمالية ومنطقة المدينة المنورة ومنطقة تبوك.<br />\r\n	وقال البكران إن هذه التعيينات لكتاب العدل تأتي لدعم الشؤون التوثيقية في كافة الدوائر الشرعية التابعة لوزارة العدل في مختلف مناطق المملكة وتحقيقاً لأهداف مشروع خادم الحرمين الشريفين لتطوير مرفق القضاء.<br />\r\n	واختتم البكران تصريحه مشيراً إلى أن عدد كتاب العدل الحاليين بالمملكة والذين يعملون بكتابات العدل الأولى والثانية والمدمجة بلغ (820) كاتب عدل يعملون على إجراء أعمال وشؤون التوثيق في اختصاصات كتابات العدل.</span></span></span></strong></p>\r\n<p data-mce-style=\"text-align: left;\" dir=\"RTL\" style=\"text-align: justify;\">\r\n	<strong><span style=\"font-family:arial,helvetica,sans-serif;\"><span style=\"font-size:16px;\"><span style=\"color:#696969;\">جريدة الرياض - الخميس 12-9-2013م</span></span></span></strong></p>\r\n', 2, '9.jpg', 'ACTIVE', '6-4-2014 7:43  صباحا', 'AR', '2016-07-02 21:59:59', '2018-04-08 08:13:49', '2018-04-08 08:13:49'),
(2, 'جدة.. تفعيل المحاكم الإلكترونية بـالأحوال الشخصية', '<p dir=\"RTL\" style=\"text-align: justify;\">\r\n	<span style=\"font-size:16px;\"><strong><span style=\"font-family:arial,helvetica,sans-serif;\"><span style=\"color:#696969;\">جدة-نسرين نجم الدين:<br />\r\n	شغلت وزارة العدل أمس نظام المحاكم الإلكترونية في محكمة الأحوال الشخصية بمحافظة جدة، أوضح ذلك لـالوطن رئيس محكمة الأحوال الشخصية بجدة الشيخ إبراهيم القني.<br />\r\n	وأشار إلى أنه تم إدخال الحاسب الآلي في محكمة الأحوال الشخصية، متوقعا أن تلك الخطوة ستسهم في تقليص قوائم انتظار المراجعين والمتقاضين في المحكمة. وأفاد بأن تشغيل نظام المحاكم الإلكترونية بالمحكمة سيقلص إجراءات الطلاق والزواج، مطالبا مراجعي المحكمة بالتقدم حاليا، لإنهاء إجراءاتهم بناء على التطوير الجديد في المحكمة.<br />\r\n	ولفت إلى أنه تم تفعيل الشبكة الإلكترونية في كافة مكاتب المحكمة وربطها بجميع الأقسام، كما تم ربط الشبكة الإلكترونية فيها بمركز المعلومات بالرياض.<br />\r\n	وكانت إدارة تقنية المعلومات في وزارة العدل قد صرحت بأن نظام المحاكم الإلكتروني يعمل في 51 محكمة وهو يضمن سلامة إصدار الصكوك كما يوزع القضايا بترتيب يتناسب وحجم القضايا مع كل مكتب قضائي. وأفادت بأن النظام يعمل على تسجيل بيانات تلك الصكوك وفق آلية منظمة يمكن الرجوع إليها في أي وقت، إلى جانب إتاحته معرفة نسب الإنتاجية التي تصدرها المحاكم وآليات العمل.<br />\r\n	ولفتت إلى أن التحول لاستخدام التقنية يأتي كأحد المحاور المهمة لمشروع خادم الحرمين الشريفين الملك عبدالله بن عبدالعزيز لتطوير مرفق القضاء.</span></span></strong></span></p>\r\n<p data-mce-style=\"text-align: justify;\" dir=\"RTL\" style=\"text-align: justify;\">\r\n	<span style=\"font-size:16px;\"><strong><span style=\"font-family:arial,helvetica,sans-serif;\"><span style=\"color:#696969;\">الصكوك كما يوزع القضايا بترتيب يتناسب وحجم القضايا مع كل مكتب قضائي. وأفادت بأن النظام يعمل على تسجيل بيانات تلك الصكوك وفق آلية منظمة يمكن الرجوع إليها في أي وقت، إلى جانب إتاحته معرفة نسب الإنتاجية التي تصدرها المحاكم وآليات العمل.<br />\r\n	ولفتت إلى أن التحول لاستخدام التقنية يأتي كأحد المحاور المهمة لمشروع خادم الحرمين الشريفين الملك عبدالله بن عبدالعزيز لتطوير مرفق القضاء.</span></span></strong></span></p>\r\n<p data-mce-style=\"text-align: left;\" dir=\"RTL\" style=\"text-align: justify;\">\r\n	<span style=\"font-size:16px;\"><strong><span style=\"font-family:arial,helvetica,sans-serif;\"><span style=\"color:#696969;\">جريدة الوطن - الخميس 19 سبتمبر 2013</span></span></strong></span></p>\r\n', 2, '9.jpg', 'ACTIVE', '6-4-2014 7:45  صباحا', 'AR', '2016-07-02 21:59:59', NULL, NULL),
(3, 'قضاة من العدل وديوان المظالم يناقشون تنفيذ الأحكام الأجنبية', '<p data-mce-style=\"text-align: justify;\" dir=\"RTL\" style=\"text-align: justify;\">\r\n	<span style=\"color:#696969;\"><span style=\"font-size:16px;\"><span style=\"font-family:arial,helvetica,sans-serif;\"><strong>الجزيرة - وهيب الوهيبي:<br />\r\n	نظمت وزارة العدل ورشة عمل بعنوان: (تنفيذ الأحكام الأجنبية) بمشاركة قضاة دوائر تنفيذ الأحكام الأجنبية بوزارة العدل وديوان المظالم بمدينة الرياض. وتناولت الورشة التي حضرها وكيل وزارة العدل لشؤون الحجز والتنفيذ الشيخ خالد بن علي آل داود موانع تنفيذ الحكم أو الأمر أو المحرر الأجنبي غير المنصوصة في نظام التنفيذ, ضابط الإخلال بأمن المملكة أو الاعتداء على السيادة في غير قضايا العقار, عرض بعض المبادئ والنماذج التطبيقية لتنفيذ الأحكام الأجنبية, تنفيذ الأحكام الأجنبية في المسائل الشخصية, تنفيذ الأحكام الأجنبية الصادرة من الدول العربية بموجب اتفاقية الرياض للتعاون القضائي, تنفيذ الأحكام الأجنبية الصادرة من عموم الدول بموجب اتفاقية نيويورك.<br />\r\n	وحيث تم نقل اختصاص تنفيذ الأحكام الأجنبية من ديوان المظالم إلى دوائر التنفيذ التابعة لوزارة العدل، فقد رأت الوزارة إقامة هذه الورشة بين الجهتين، وذلك لتبادل الخبرات والاستفادة من الخبرة الطويلة التي اكتسبها الديوان في هذا المجال.<br />\r\n	وتحرص الوزارة على النهوض بقضاء التنفيذ، حيث تم زيادة عدد قضاة التنفيذ إلى (297) قاضياً في جميع مناطق المملكة، كما أنشأت وكالة الوزارة لشؤون الحجز والتنفيذ وتم إعداد خطة تدريبية تم من خلالها تدريب (100) قاضي تنفيذ و (500) موظف من موظفي دوائر التنفيذ حتى الآن، وذلك لضمان فاعلية نظام التنفيذ والوصول به إلى النتيجة المُرضية التي يتطلع لها الجميع من خلال سرعة الإنجاز وتوحيد الإجراء ودقة وإتقان العمل.</strong></span></span></span></p>\r\n<p data-mce-style=\"text-align: left;\" dir=\"RTL\" style=\"text-align: justify;\">\r\n	<span style=\"color:#696969;\"><span style=\"font-size:16px;\"><span style=\"font-family:arial,helvetica,sans-serif;\"><strong>جريدة الجزيرة - الاربعاء 12 ذو القعدة 1434</strong></span></span></span></p>\r\n', 2, '10.jpg', 'ACTIVE', '6-4-2014 7:49  صباحا', 'AR', '2016-07-02 21:59:59', NULL, NULL),
(4, 'المحامي الجريس: «العدل» مختصة بمتابعة شؤون المحامين', '<p data-mce-style=\"text-align: justify;\" dir=\"RTL\" style=\"text-align: justify;\">\r\n	<strong><span style=\"font-family:arial,helvetica,sans-serif;\"><span style=\"font-size:16px;\"><span style=\"color:#696969;\">الرياض-مبارك بن سعد:<br />\r\n	أكد عبد الرحمن الجريس رئيس مجموعة الجريس للمحاماة والاستشارات والتدريب ومحامي الموقوفين في القضايا الأمنية والمعتقلين السعوديين في الخارج، أن تصريح المتحدث الرسمي لوزارة العدل حول مراقبة تغريدات المحامين في «تويتر» لا يدعو للتصعيد ولا يثير الحفيظة، وأكد أن «وزارة العدل مختصة بمتابعة شؤون المحامين من كافة الجوانب حسب النظام». جاء ذلك في تصريح خص به «الرياض»، وقال فيه حول هذا الموضوع: «لقد رأيت في الفترة القريبة استياء بعض الزملاء المحامين من تصريحات المتحدث الرسمي بشأن الرقابة على سلوكيات المحامين في وسائل الإعلام، وهذا التصريح لحقه تصريح آخر يفسر ويوضح المقصود، ولا أجد فيه ما يثير الحفيظة أو يدعو للتصعيد ونحن المحامين نعتبر وزارة العدل حصناً لنا نأمل فيها الكثير، وكم تمنيت أن يكون التعاطي مع هذا التصريح بعد التثبت ومراعاة الموضوعية وليس أسهل من التواصل مع المتحدث الرسمي ومناقشته حول ذلك، خصوصاً أن مهنة المحاماة تعتبر نصف القضاء ولا يحكم الإنسان على شيء حتى يتصوره بشكل واضح ولعل ما دار في الأيام الماضية يقوي ويزيد الصلة بين المحامين وزارة العدل».<br />\r\n	وحول أحقية وزارة العدل بمتابعة سلوك المحامين أجاب الجريس«لا يخفى على الجميع أهمية وزارة العدل وما ينتظر منها من ادوار كبيرة في سبيل تحقيق العدالة، ووزارة العدل تعتبر حسب النظام جهة مختصة بمتابعة شؤون المحامين من كافة الجوانب ولا أظن أن المحامي الموضوعي يزعجه ذلك ويعلم المختصون أن نظام المحاماة قد كُلفت وزارة العدل بإصدار لائحته التنفيذية، وصياغة هذه اللائحة ووضع موادها وتفسيرها من صلاحيات وزير العدل، وكون المحامي يعبر عن رأيه في وسائل الإعلام فهذا يعتبر إذناً صريحاً ليس للوزارة فحسب بل للمجتمع كاملاً بممارسة دورهم الرقابي عليه وهذا لا يحتاج لنظام أو إذن من احد».<br />\r\n	واختتم الجريس تصريحه قائلاً «بصفتي عضواً في عددٍ من اللجان والجمعيات الوطنية والإقليمية ومنها اللجنة الوطنية للمحامين ولجنة المحامين بالغرفة التجارية والصناعية بالرياض أوجه شكري لمعالي وزير العدل على مواقفه مع المحامين في العديد من المطالب التي رفعت له لتطوير للمهنة وإعطائها مكانتها، وإنني من خلال مقابلاتي لمعالي الوزير وجدت منه اهتماماً كبيراً وأطلق وعوداً جميلة لو تمت دون عوائق سيكون فيها الخير الكثير إن شاء الله».</span></span></span></strong></p>\r\n<p data-mce-style=\"text-align: left;\" dir=\"RTL\" style=\"text-align: justify;\">\r\n	<strong><span style=\"font-family:arial,helvetica,sans-serif;\"><span style=\"font-size:16px;\"><span style=\"color:#696969;\">جريدة الرياض -  الموافق 19 سبتمبر 2013</span></span></span></strong></p>\r\n', 2, '11.jpg', 'ACTIVE', '6-4-2014 7:51  صباحا', 'AR', '2016-07-02 21:59:59', NULL, NULL),
(5, 'تخريج متدربي تنفيذ الأحكام القضائية', '<p data-mce-style=\"text-align: justify;\" dir=\"RTL\" style=\"text-align: justify;\">\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\"><strong><span style=\"color:#696969;\"><span style=\"font-size:16px;\">جدة-محمد الزايد: <br />\r\n	شهدت جدة تخريج أول دفعة من المستشارين القانونيين والمحامين المشاركين في برنامج تدريبي حول نظام التنفيذ الجديد باعتماد المؤسسة العامة للتدريب التقني والمهني.<br />\r\n	وأوضح رئيس مجلس أمناء مركز مكة الدولي للتوفيق والتحكيم والمصالحة رئيس الاتحاد العربي للتوفيق والتحكيم الدولي الدكتور فهد بن مشبب آل خفير في تصريح أن البرنامج تمكن من تنمية المهارات الفنية والعملية للمشاركين وتمكينهم من معرفة أحكام نظام التنفيذ الجديد.<br />\r\n	وبين أن البرنامج أسهم كذلك في معرفة دور قاضي التنفيذ في تطبيق نظام التنفيذ الجديد، بالإضافة إلى تمكين المتدربين من معرفة صلاحيات المحامي أو الوكيل الشرعي في مرحلة التنفيذ وكيفية تحقيقها على أكمل وجه للوفاء بمتطلبات عملية، والتعرف على ماهية عقبات التنفيذ وكيفية التغلب عليها وأساليب سرعة وتأخير التنفيذ والعقوبات المترتبة على ذلك، بالإضافة إلى كل ما هو جديد في هذا النظام.</span></span></strong></span></p>\r\n<p data-mce-style=\"text-align: left;\" dir=\"RTL\" style=\"text-align: justify;\">\r\n	<span style=\"font-family:arial,helvetica,sans-serif;\"><strong><span style=\"color:#696969;\"><span style=\"font-size:16px;\">جريدة الوطن - السبت21سبتمبر2013</span></span></strong></span></p>\r\n', 2, '9.jpg', 'ACTIVE', '6-4-2014 7:52  صباحا', 'AR', '2016-07-02 21:59:59', NULL, NULL),
(6, '«العدل» تحصد جائزة التميز الإلكتروني للحكومات على مستوى الشرق الأوسط', '<p>\r\n	الرياض- اسامة الجمعان</p>\r\n<div id=\"article_text\">\r\n	<p>\r\n		    حصلت وزارة العدل على جائزة الشرق الأوسط للتميز (19) للحكومة والخدمات الالكترونية. وتسلم الجائزة مدير مشروع الملك عبدالله لتطوير القضاء المهندس ماجد بن إبراهيم العدوان خلال الحفل السنوي الذي أقامه معهد جائزة الشرق الأوسط للتميز لأفضل الانجازات والمبادرات والممارسات في تطوير استراتيجيات التحول الالكتروني في دبي الأربعاء.</p>\r\n	<p>\r\n		وتسلمت الوزارة الجائزة على هامش فعاليات المؤتمر العشرين للحكومة والخدمات الإلكترونية في دول مجلس التعاون الخليجي والذي أقيم بمركز دبي المالي العالمي بمشاركة سعودية وإقليمية ودولية واسعة من كبرى المنظمات والمؤسسات الحكومية والخاصة والذي يستعرض فيه المشاركون أحدث التطورات والأبعاد الإستراتيجية في مشاريع الحكومة والتعاملات الإلكترونية، ومناقشة المبادرات والتوجهات العالمية الجديدة، وسبل الاستفادة من الخبرات الإقليمية والدولية نحو قيادة التحول المؤسسي نحو خدمات الحكومة الذكية.</p>\r\n	<p>\r\n		وعبر المهندس العدوان عن سعادته بحصول وزارة العدل على هذه الجائزة المهمة على مستوى الشرق الأوسط والتي أثبتت جودة الخدمات الالكترونية المقدمة للمستفيدين من خدمات الوزارة، مضيفاً أن الوزارة تعمل بشكل دؤوب على تطوير الخدمات الالكترونية وتقديم خدمة أفضل لأصحاب الفضيلة القضاة وكُتاب العدل وتيسير أعمالهم مع تقديم الخدمات التي سهلت للمستفيدين سرعة انجاز وكالاتهم وأعمالهم مع حفظها لسرية معلوماتهم وتوثيقها.</p>\r\n	<p>\r\n		من جهته، أكد الرئيس التنفيذي لمعهد الجائزة علي الكمالي أهمية الجهود التي تبذل للاستفادة من الخبرات وأفضل الممارسات الإقليمية والدولية في قيادة التحول المؤسّسي وبناء استراتيجيات حوكمت المؤسّسات وآليات إدارة التخطيط والأداء المؤسّسي المتطور.</p>\r\n</div>\r\n<p>\r\n	 </p>\r\n', 2, '18.jpg', 'ACTIVE', '6-6-2014 10:57  صباحا', 'AR', '2016-07-02 21:59:59', NULL, NULL),
(7, '«العدل» تدعو المتقدمين للوظائف الإدارية بالمرتبة السادسة لدخول البوابة الإلكترونية', '<p style=\"text-align: justify;\">\r\n	الرياض - مبارك العكاش</p>\r\n<p style=\"text-align: justify;\">\r\n	أعلنت وزارة العدل أسماء (1931) مرشحاً على الوظائف (مقدر أملاك مساعد ومحاسب مساعد مأمور تنفيذ وأمين صندوق ومساح) بالمرتبة السادسة والتي سبق لوزارة العدل الإعلان عن التقديم عليها.</p>\r\n<div id=\"article_text\">\r\n	<p style=\"text-align: justify;\">\r\n		ودعت الوزارة المرشحين الذين اجتازوا الامتحان التحريري الدخول على بوابة الوزارة الإلكترونية (<a href=\"http://www.moj.gov.sa/\" target=\"_blank\">www.moj.gov.sa</a>) وطباعة بطاقة المقابلة الشخصية والتي ستبدأ اعتباراً من يوم الاحد القادم 3/8/1435ه والتي تتضمن تاريخ ووقت ومقر المقابلة ورقم اللجنة، مع مراجعتهم لفرع الوزارة في المنطقة المتقدمين لوظائفها في وقت مبكر قبل موعد المقابلة لاستكمال الملف.</p>\r\n	<p style=\"text-align: justify;\">\r\n		وأوضح مدير عام الشؤون المالية والإدارية الأستاذ محمد عبدالله العقيل أن الوزارة تهدف بإشغال هذه الوظائف سد حاجتها من الموظفين في جميع دوائرها الشرعية وذلك ضمن خطتها إلى الاستفادة من الموارد البشرية المؤهلة في تطوير العمل القضائي والتوثيقي وشغل الوظائف الشاغرة في الدوائر العدلية دعما للتشكيلات الوظيفية للدوائر الجديدة والقائمة بما تحتاجه من موظفين.. مشيرا الى أن وظائف المرتبة الرابعة (مراقب أمن وسلامة) والتي تقدم الاعلان عنها في نفس التوقيع سيتم التنويه عنها في وقت لاحق.</p>\r\n</div>\r\n<p>\r\n	 </p>\r\n', 2, '9.jpg', 'ACTIVE', '6-6-2014 11:00  صباحا', 'AR', '2016-07-02 21:59:59', NULL, NULL),
(8, '« العدل» تطلب من الجهات الحكومية إنشاء سحابة إليكترونية لتبادل المعلومات', '<p style=\"text-align: justify;\">\r\n	الرياض – أسمهان الغامدي</p>\r\n<div id=\"article_text\">\r\n	<p style=\"text-align: justify;\">\r\n		طلبت وزارة العدل من الجهات الحكومية إنشاء سحابة إلكترونية لتسهيل تبادل المعلومات بين الجهات والاستفادة منها وتوفير الخدمات المعلوماتية الدائمة مع جميع الجهات الحكومية, كما تعمل على تنفيذ مشروع مركز معلومات احتياطي لحفظ البيانات</p>\r\n	<p style=\"text-align: justify;\">\r\n		قال هذا مدير مشروع الملك عبدالله بن عبدالعزيز لتطوير مرفق القضاء المهندس ماجد العدوان خلال الدورة الخامسة لقمة الحكومة الالكترونية الذي استضافته مؤخرا الرياض وذلك بتنظيم من مجموعة (نسيبا) وبدعم من برنامج التعاملات الإلكترونية الحكومية (يسّر)، وبمشاركة عدد من الخبراء والمهتمين في مجال التعاملات الإلكترونية الحكومية.</p>\r\n	<p style=\"text-align: justify;\">\r\n		وأكد أن نظام البصمة الإلكترونية للتحقق من الهوية المربوط مع وزارة الداخلية أسهم في التخفيف عن العاملين بوزارة العدل والمراجعين، كما حدّ من عمليات انتحال الهوية, منوها بجهود الوزارة في توفير مركز معلومات يعتبر من أحدث مراكز المعلومات في الشرق الأوسط.</p>\r\n	<p style=\"text-align: justify;\">\r\n		هذا وقد نالت تجربة وزارة العدل في الربط الالكتروني مع وزارة الداخلية وتطبيقها نظام البصمة الالكتروني الجزء الأكبر من اهتمام المشاركين، وهدفت القمة إلى زيادة الوعي حول التعاملات الإلكترونية الحكومية، والعمل على إظهار تأثيرها الإيجابي والسريع على الأنشطة والأعمال اليومية للجهات الحكومية، وما تقدمه من خدمات للمواطنين والقطاع الخاص، كما توفر فرصة للمشاركين للقاء أبرز شركات توفير الحلول التقنية على مستوى العالم، لمناقشة الخطط المستقبلية للحكومة الإلكترونية. وتعد القمة فرصة مواتية لاستعراض أبرز المشاريع والمنتجات الإلكترونية الحكومية، ومناقشة طرق تنفيذها، إضافة إلى أنها تعد تجمعاً لعدد من المهتمين والعاملين بمجال التعاملات الإلكترونية الحكومية في المملكة ودول مجلس التعاون لدول الخليج العربية.</p>\r\n</div>\r\n<p>\r\n	 </p>\r\n', 2, '19.jpg', 'ACTIVE', '6-6-2014 11:02  صباحا', 'AR', '2016-07-02 21:59:59', NULL, NULL),
(9, 'وزير العدل: القضاء في المملكة يحمي المشروعية والحقوق والحريات العامة المشروعة', '<p>\r\n	الرياض - أسامة الجمعان</p>\r\n<div id=\"article_text\">\r\n	<p>\r\n		    أوضح وزير العدل الشيخ الدكتور محمد بن عبد الكريم العيسى أن النظام العدلي في المملكة العربية السعودية بدأ مثل غيره بأعراف إجرائية تحولت إلى أول بداية لإجراءاته المكتوبة التي تنظم سير عمل المحاكم وذلك عام 1372ه (1953)، تلا ذلك أول نظام متكامل للسلطة القضائية عام 1395ه (1975) وهو ما تم تحديثه عام 1428ه (2007)، كما أن هناك أنظمة خاصة لبعض المحاكم سابقة لهذه التواريخ، مثل نظام المحكمة التجارية الذي صدر عام 1350ه (1931)، كما تلا إجراءات عام 1372ه (1953) إصدار نظام المرافعات الشرعية (نظام المرافعات المدنية) عام 1421ه (2000)، ونظام الإجراءات الجزائية عام 1422ه (2001) ثم تم تعديلهما بنظامين جديدين هذا العام 1435ه (2014).</p>\r\n	<p>\r\n		استمرار إصلاحات الإجراءات القضائية يعكس مرونة وتطور عملنا العدلي</p>\r\n	<p>\r\n		وأشار وزير العدل في محاضرته على قيادات وأعضاء الاتحاد الدولي للمحامين في اجتماعهم المنعقد بنيويورك، بناء على دعوة الاتحاد لمعاليه، وفي لقائه التالي بفعاليات حقوقية وأكاديمية أشار إلى أن أهم ملامح نظام السلطة القضائية النافذ حالياً هو إعطاء المزيد من دعم استقلال السلطة في أحكامها كما هي المسلمة الدستورية في المملكة، وكذلك إعطاء تنوع في المجلس الأعلى للقضاء لتشمل عضويته كافة الطيف ذي الصلة بالشأن القضائي من أجل أن تتكامل من خلاله الحيادية في تدبير الشؤون الوظيفية للقضاة، وقريب منه مجلس القضاء الإداري.</p>\r\n	<p>\r\n		 </p>\r\n	<div>\r\n		 </div>\r\n	المملكة في قائمة الدول الأسرع والأكثر مرونة في التحديثات الإصلاحية مقارنة بعمرها الزمني\r\n	<div>\r\n		 </div>\r\n	<p>\r\n		 </p>\r\n	<p>\r\n		 </p>\r\n	<p>\r\n		كما أنشأ النظام النافذ للسلطة القضائية محكمتين عُليين الأولى للقضاء العام والثانية للقضاء الإداري، حيث تأخذ المملكة بنموذج القضاء المزدوج، ولا يعني هذا وجود فراغ في القضاء العالي في السابق لكون الأمر لا يعدو سوى إعادة صياغة المحكمتين مجدداً، ومثله تماماً إنشاء محاكم الاستئناف حيث كانت في السابق بصيغة معينة ثم تطورت إلى صيغة أكثر تحديثاً، ووسع النظام النافذ حالياً من مفهوم التخصص النوعي في نظر القضايا، كما تم إنشاء دوائر نوعية متخصصة داخل محكمة التخصص النوعي نفسها، وهذا خدم في جودة المخرج القضائي بشكل أكثر تنظيماً وتركيزاً.</p>\r\n	<p>\r\n		وأشار الوزير إلى أن الكليات العامة للعدالة متفق عليها بين الجميع لكن الاختلاف في بعض القواعد، وكذلك أيضاً في التفاصيل الفرعية، وأن هذا الاختلاف يجري داخل الأقاليم والولايات ذات الحكم المحلي في الدولة الواحدة وليس فقط من دولة لدولة، وهذا واضح ومعروف للجميع.</p>\r\n	<p>\r\n		 </p>\r\n	<p>\r\n		 </p>\r\n	<div>\r\n		<img src=\"http://s.alriyadh.com/2014/06/01/img/121549623319.jpg\" title=\"حضور كثيف للمحامين والحقوقيين والأكاديميين الدوليين في محاضرة د. العيسى \" />\r\n		<div>\r\n			 </div>\r\n		<br />\r\n		حضور كثيف للمحامين والحقوقيين والأكاديميين الدوليين في محاضرة د. العيسى</div>\r\n	<p>\r\n		 </p>\r\n	<p>\r\n		 </p>\r\n	<p>\r\n		مبيناً أن القضاء في المملكة يعتمد في أحكامه على احترام النص الإسلامي في كافة المواد القضائية، غير أن هذا النص كما هي حكمة المشرع الإلهي لا يتدخل في كثير من تلك المواد وبالتحديد في المواد المدنية والتجارية والجنائية، وفيما لا يكون فيه نص يُقنِّن حكم الواقعة القضائية فإن السلطة التقديرية للقضاء تتصدى لشغل الفراغ باجتهادها المبني بلا شك على خبرتها وتأهيلها والتي يجب أن يتم تتويج اجتهادها حتى يكون مبدأ من مبادئ العدالة وسابقة قضائية ملزمة بواسطة إقرار المحكمة العليا لهذا الاجتهاد، ومعنى هذا أن المنظم السعودي وبحسب الأحوال يتصدى لسن التنظيمات المحلية ولا يسع القضاء إلا احترامها إذا لم تخالف الدستور، فالمدرسة القضائية في المملكة لا تختلف كثيراً عما يسمى بمدرسة المزج بين النموذج اللاتيني والأنجلوسكسوني والذي أصبح مؤخراً سمة كثير من الدول بما فيها أصحاب تلك المدارس، وبالطبع كل على حدة، واستطرد في ذات السياق قائلاً: \"إن سوابق القضاء هي بطبيعة الحال الأقرب لتعزيز استقلاله والأدق لتحقيق تجانس وقائع القضية مع أسباب حكمها\"، مضيفاً بناء على سؤال في هذه الجزئية بأن تعدد الاجتهاد في النص الإسلامي يماثل تعدده في النص الوضعي والمبادئ القضائية المختارة من المحكمة العليا تضمن استقرار الأحكام.</p>\r\n	<p>\r\n		وتحدث الوزير عن المبادئ المسلم بها في النظام العدلي بالمملكة ومن أهمها حق اللجوء للقضاء الطبيعي \"فلا قضاء استثنائياً في المملكة على الإطلاق، وهناك بعض اللجان المدنية والتجارية ذات صفة قضائية وهي عموماً بنفس الضمانات التأهيلية وبنفس ضمانات الدرجات القضائية، أقصد بالطبع في سياقها إطارها الخاص، ويجري حالياً عمل دراسة لترتيب إجرائي جديد لها ربما يشملها قريباً بنفس الترتيب العام للقضايا المدنية والتجارية مع أني أؤكد مجدداً بأن الضمانات الفنية في عدالتها موجودة.</p>\r\n	<p>\r\n		ومن المبادئ المسلم بها في النظام العدلي للمملكة تعدد درجات التقاضي من محاكم ابتدائية إلى محاكم استئنافية إلى محكمة عليا بحسب ما ينص عليه نظام السلطة القضائية في كل من هذه المحاكم وعلى وجه الخصوص المحكمة العليا، ومن المبادئ أيضاً علانية المرافعات ليراقب الجميع حسن سير العدالة، وكذلك حق أي من أطراف الدعوى في الاستعانة بمحام في جميع مراحل سير القضية، وأيضاً من هذه المبادئ مجانية التقاضي ولم يقتصر الأمر على ذلك بل وصلنا إلى تقديم المعونة القضائية لغير القادرين على دفع تكاليف المحاماة وتحديداً في القضايا الجزائية، ولا يعني هذا المبدأ السماح بالتوظيف السلبي له من خلال نشاط الدعاوى الكيدية وغير الجدية، فالقضاء يتصدى لذلك بالعقوبات بحسب لائحة تنظيمية في ذلك، على أننا نسعى حالياً لإيجاد صيغة نظامية أكثر تطويراً لها من خلال اقتراحنا على الجهة التشريعية بالسماح بفرض تكاليف معينة على الخاسر، وللقضاء وفق سلطته التقديرية أن يُعفي من الرسم على أساس أن الأصل هو مجانية التقاضي حيث أننا نؤمن بأنه لا ثمن للعدالة، لكن لا بد من إجراءات تحفظية لإكساب رفع الدعوى المزيد من ضمانات الجدية، فإذا اتضح للقاضي ذلك فإنه يعفي الخاسر من التكاليف على أساس الأصل كما أشرت إليه قبل قليل\".</p>\r\n	<p>\r\n		 </p>\r\n	<div>\r\n		 </div>\r\n	الفهم الخاطئ وأحادية المصدر وتجاهل التنوع الثقافي سبب جسامة أخطاء بعض التقارير الحقوقية\r\n	<div>\r\n		 </div>\r\n	<p>\r\n		 </p>\r\n	<p>\r\n		 </p>\r\n	<p>\r\n		وتحدث الوزير عن خطة وزارته في تفعيل أسلوب بدائل التقاضي، وقال إن منها تفعيل فكرة الصلح بعمل مؤسسي حيث استصدرت وزارة العدل نظاماً لهذا الخيار الفعال، وأنشأت وكالة باسمه ومن خلاله أنشأت وحدة للعمل الاجتماعي في المحاكم، ووقعت اتفاقية مع وزارة الشؤون الاجتماعية لدعم هذه الوحدة والتي تنوي وزارة العدل تحويلها إلى وكالة لشؤون الأسرة لخدمة عمل المحاكم في هذا الجانب، وبالتحديد الحد من تدفق القضايا للقضاء والأهم منه لم شمل الأسرة وإصلاح شأنها داخلياً، متى ما أتيحت الفرصة لوزارة العدل من خلال الجهة المسؤولة عن الهيكلة الإدارية للوزارات.</p>\r\n	<p>\r\n		ومن بدائل التقاضي التحكيم والذي صدر أول نظام له عام 1403ه (1983) والذي تم لاحقاً تحديثه بنظام جديد عام 1433ه (2012) وقد راعى التحديث تسهيل إجراءات التحكيم وإعطاءه المزيد من الاعتماد والموثوقية ومن ذلك أن الطعن على الحكم التحكيمي يتم أمام محكمة الاستئناف مباشرة، ومنع القضاء من التدخل في موضوع الحكم التحكيمي، وإكساب وثيقة التحكيم المزيد من المرونة، كما تم هذا العام إنشاء مركز تحكيم تجاري يضم بحسب نظامه كذلك بعض القضايا المدنية.</p>\r\n	<p>\r\n		 </p>\r\n	<div>\r\n		 </div>\r\n	المرأة السعودية حقوقية مهنية وبرلمانية بصيغة إسلامية\r\n	<div>\r\n		 </div>\r\n	<p>\r\n		 </p>\r\n	<p>\r\n		 </p>\r\n	<p>\r\n		كما تم في العام الماضي إصدار نظام التنفيذ بعد أن كان التنفيذ يتم من خلال أحكام متفرقة وجهات متعددة فأوكل النظام ذلك لقاضي التنفيذ وأعطاه صلاحيات واسعة جداً، كما وسع النظام من مفهوم سندات التنفيذ، وهو ما خفف كثيراً من أعباء نظر الكثير من القضايا، كما يختص قاضي التنفيذ بتنفيذ الأحكام القضائية الأجنبية والأحكام التحكيمية الأجنبية بشرط وجود اتفاقية ثنائية أو إطارية أو دولية مصادق عليها أو معاملة بالمثل، ونبه الوزير على أن القضاء يُكَيِّف الاتفاقات والمعاهدات والمواثيق الدولية المصادق عليها من قبل المملكة في سياق عدم تقاطعها مع النظام العام للدولة، على أنها ذات طابع أعلى في التدرج التنظيمي عند اختلافها مع التنظيمات المحلية لاعتبارات تتعلق باحترام الدولة لكلمتها.</p>\r\n	<p>\r\n		وحول القضاء التجاري أشار الوزير إلى أنه لا يقتصر فقط على الفصل في المنازعات التجارية بل يحمي الساحة التجارية من خلال العديد من الإجراءات القضائية، ومنها الصلح الواقي من الإفلاس، واستمرار كيان الشركة أثناء التصفية.</p>\r\n	<p>\r\n		وحول المحاماة في المملكة قال الوزير إن المحاماة تتمتع بالاستقلال في عملها المهني فلا يتدخل أحد في شؤونها، وعلى المحامين احترام أحكام نظام المحاماة ولائحته، مشيراً إلى أن للمحاماة لجنة وطنية ستتحول إلى هيئة بنظام خاص، وأكد الوزير على أن المحامي السعودي أصبح دولياً وهو بحسب استطلاعاتنا الأقل في مخالفاته المهنية فدائرة الجزاء المعنية بالمخالفات نادراً ما تصدر عقوبات على المحامي السعودي، بالرغم من متابعتها الدقيقة لسلوكياته المهنية وفتح المجال بحسب نظام المحاماة لتلقيها شكاوى الجهات القضائية والأفراد، وهو دليل على مستوى المهنية والانضباط العالي.</p>\r\n	<p>\r\n		وقال \"إن الوزارة تدعم مهنة المحاماة ولا تتدخل في شؤونها الموضوعية وتشرف عليها إشرافاً داعماً من أجل رعايتها والاطمئنان على حسن سيرها، فنحن في وزارة العدل نعتبر المحاماة الشريك الأهم في إيصال العدالة والمعاون الأول للقضاء، وهي بحسب النظرية القانونية القضاء الواقف، ونرعى استقلالها كما نرعى استقلال القضاء تماماً، لكن ما من عمل مهني إلا وله رقابة عامة تضمن حسن سيره، ولا تتدخل في شؤونه الموضوعية وإلا أصبح هناك تكتل مهني يدافع عن نفسه ليس في شأنه الخاص المنغلق على ذاته بل فيما يتعلق بمصالح المؤسسات والأفراد ونزيد هنا بمصلحة العدالة وسمعتها، وهو في جملة التعاون التكاملي بين سلطات الدولة ومؤسسات النفع العام، كما هو التوجه العصري الحديث\".</p>\r\n	<p>\r\n		وقال الوزير \"إن نظام العدالة في المملكة تشريعاً وممارسةً كتاب مفتوح للجميع ونستمع لوجهات النظر ونتحاور حولها ونستفيد منها بما يمليه منطق الحكمة فالكثير من الجوانب الإجرائية استفدناها من غيرنا سواء من اطلاعنا على الأنظمة الدولية، أو من خلال جولاتنا الاستطلاعية والحوارية، وهدفنا كما هو هدف كافة الحكماء الوصول لكل مفيد من شأنه أن يخدم ويسهل إجراءات العدالة، وكانت أول استفادة لنا من الممارسات الدولية في خدمة إجراءات المحاكم كما قلنا تمت وفق نظام إجرائي صدر عام 1350ه (1931) وآخر صدر عام 1372ه (1953) موضحاً معاليه أن استمرار تحديث الإجراءات القضائية يعكس مرونة وتطور العمل العدلي\".</p>\r\n	<p>\r\n		وأكد وزير العدل الدكتور محمد العيسى أن قضاء المملكة العربية السعودية يعتبر بكل اعتزاز وفخر حامي المشروعية والحقوق والحريات العامة المشروعة، مشيراً إلى أن المبادئ الدستورية والقانونية تمنع تجاوز الحريات لدساتير وقوانين الدول، وأن احترام النظام العام مُسَلَّمة سيادية لكل دولة، وأن الرأي المجرد مرحب به في عدالة الإسلام ويترجم أهم روافد الدعم التنظيمي والإصلاحي، منبهاً في ذات السياق إلى أنه يجب أن يقف سقف الحريات عند حدود احترام النصوص التشريعية والقيم الأخلاقية والأعراف العامة بحسب كل ثقافة.</p>\r\n	<p>\r\n		وحول سؤال عن الدور القانوني للمرأة السعودية، قال الوزير: \"إن المرأة أصبحت حقوقية مهنية تمارس المحاماة برخصة لا مجرد وكيلة بتفويض عابر كما كانت في السابق، وأصبحت برلمانية بصيغة إسلامية، ودخلت عضوية المجالس البلدية، بل إن نسبة عضويتها في مجلس الشورى تفوق نسبة عضوية المرأة في برلمانات بلدان كبرى.</p>\r\n	<p>\r\n		وحول سؤال عن عدم الاتفاق على تفسير النص الإسلامي، وكيف يكون بالتالي صيغة تشريعية في قضايا مدنية وتجارية وجنائية، قال الوزير: \"إن تعدد الاجتهاد في النص الإسلامي يماثل تعدده في النص الوضعي والمبادئ المختارة تضمن استقرار الأحكام، بل إن التعدد يزيد من ثراء المادة الفقهية الإسلامية كما هو في المادة القانونية\".</p>\r\n	<p>\r\n		وتحدث الدكتور محمد العيسى عن وجود رقابة حقوقية في المملكة حكومية وأهلية وأنها تُصْدِر تقارير قوية وشجاعة تنتقد علناً أي خلل أو خطأ أو تقصير أو تجاوز في المؤسسات الحكومية وتقدم مقترحاتها للإصلاحات على نطاق واسع، ثم استطرد قائلاً: \"إن بعض الهيئات والمنظمات الحقوقية العالمية يحملها اللاشعور للدعوة لثقافتها لا لحقوق الإنسان المجردة، وأنه يجب أن يسلم الغربي بأن لدى الشرقي خصائص أخلاقية وثقافية يعتز بها، كما يجب التسليم بالفروق الثقافية حتى لا نتجاوز نطاق الحكمة والموضوعية في التعامل مع الآخرين، وأن الفهم الخاطئ، وأحادية المصدر، وتجاهل التنوع الثقافي هو في الواقع سببُ جسامة أخطاء بعض التقارير الحقوقية، كما أفاض الوزير قائلاً: \"وفق الحقائق المادية تعتبر المملكة في قائمة الدول الأسرع والأكثر مرونة في التحديثات الإصلاحية مقارنة بعمرها الزمني\".</p>\r\n	<p>\r\n		وحول سؤال عن رأي العدالة السعودية في التعددية الحزبية، وهل يحل القضاء مؤسساتها بالإلغاء، قال الوزير \"إن المملكة دولة إسلامية والإسلام حزب واحد بنص وحيه الرباني، ولا يمكن أن يقبل مسلم فَهِمَ الإسلام فهماً صحيحاً أن يتفرق هذا الحزب إلى شتات أحزاب باسم الإسلام أي باسم الحزب الواحد، وقال لا يمكن أن تخضع مصالح الأمة الواحدة وهي تحت راية واحدة في سياقه حزبها الواحد لتجاذبات حزبية ربما تفوت عليها مصالح تشريعية أو إصلاحية تفوق بها التصويت البرلماني للحزب المنافس لا لشيء إلا لمنع حصول الحزب الآخر على ما يسمى بالكريدت\"، وأضاف: \"إن تغيير الأحزاب المنتسبة للإسلام أسماءها في منافساتها السياسية دليل على الرفض الإسلامي للشتات الحزبي داخل حزبه الواحد، وأكد الشيخ الدكتور محمد العيسى أن الإسلام يرفض توظيفه لتحقيق مكاسب سياسية ومادية، ونصوصه تراقب سلوك المجتمع الإسلامي وتدعو المجتمعات الأخرى للاستهداء به أو الإفادة على الأقل من تجربته التطبيقية. وحول اعتناق الأديان وموقف العدالة القضائية في المملكة منها، قال الوزير العيسى من المسلمات في دين الإسلام أنه لا إكراه في الدين، وأضاف معاليه بأنه كذلك لا إكراه على اعتناق الثقافات، مشيراً إلى أن الفكر مرتبط بالروح لا الجسد لذا فهو لا يقبل منطق القوة، ولا يُفرَض بها، والنص الدستوري لدينا الذي يقضي بأنه لا إكراه في الدين نص عام، وبالمناسبة فإن الأخذ بعموم النص الإسلامي لا بسبب وروده بنى لنا قواعد مستقرة وخالدة ومن ذلك عدم الإكراه على الدين، وهذه السعة في الاستنباط أسست للقواعد الفقهية الإسلامية تأسيساً قوياً. وعلق الوزير في هذا على سؤال جانبي فقال: \"الإسلام يشترط لاحقاً على من يعتنقه احترام قناعته التي قادته للإسلام، لأن ترك هذه القناعة قد تكون مدعاة للإساءة، فمَنَعَ الإسلام أي احتمال لها من خلال التأكيد على مريد اعتناقه بأن هذا هو شرط الدخول فيه، وهذا يترجم أن الإسلام حريص أيضاً مع ما سبق على التأكد من قناعة المعتنق بالدين الإسلامي بشكل تام لا تقبل أي احتمال لاحق، وقد حصل في عهد نبي الإسلام صلى الله عليه وسلم أن هناك مَنْ دخل في الدين لمجرد الإساءة ونزل في ذلك وحي من السماء يندد بهذا التصرف غير الأخلاقي فشرع الإسلام المنع البات لمثل هذه الحالات احتراماً لقيمة وقدسية الدين ومحافظة على سمعته، ومنع أي تسلل مسيء.</p>\r\n</div>\r\n<p>\r\n	 </p>\r\n', 2, '20.jpg', 'ACTIVE', '6-6-2014 11:05  صباحا', 'AR', '2016-07-02 21:59:59', NULL, NULL),
(10, '«العدل» تنظم حلقة نقاش الحراسة القضائية في بريدة', '<p>\r\n	الرياض - مبارك العكاش</p>\r\n<div id=\"article_text\">\r\n	<p>\r\n		    نظمت وزارة العدل حلقة النقاش (الحراسة القضائية) بمدينة بريدة بمشاركة عدد من أصحاب الفضيلة القضاة.</p>\r\n	<p>\r\n		وتناولت الحلقة التي رأسها فضيلة رئيس محكمة بريدة العامة الشيخ منصور الجوفان التعريف بالحراسة القضائية ومشروعيتها، والحراسة القضائية في نظام المرافعات الشرعية، وإقامة دعوى الحراسة القضائية والنظر في الاختصاص النوعي والمكاني، وكيفية السير في قضية الحراسة القضائية (بحث المسوغات وإصدار الحكم )، وحقوق الحارس القضائي.</p>\r\n	<p>\r\n		وفي هذا الشأن نظمت المحكمة العامة ببريدة البرنامج التدريبي للملازمين القضائيين بمشاركة (80) ملازما قضائيا بالقصيم.</p>\r\n	<p>\r\n		وتناول البرنامج الذي أقيم على مدى ثلاثة أسابيع بإقامة (10) ورش عمل حيث تناول معالي رئيس محكمة الاستئناف بالقصيم الشيخ عبدالله بن عبدالرحمن المحيسن ملحوظات التفتيش على قضاة الدرجة الأولى، في حين تناول معالي رئيس محكمة الاستئناف المساعد الشيخ إبراهيم بن علي الضالع ملحوظات الاستئناف على أحكام قضاة الدرجة الأولى، وتناول رئيس المحكمة العامة ببريدة المساعد الشيخ سليمان بن عبدالرحمن الربعي ورشتي عمل أعراف أهل البلد وأثرها في الحكم القضائي والصياغة القانونية، فيما تناول فضيلة رئيس المحكمة العامة بعنيزة الشيخ صالح بن سليمان المطرود الصلح وأثره في الحكم القضائي.</p>\r\n	<p>\r\n		كما تناول البرنامج ورشة عمل نظام التنفيذ والتي قدمها رئيس دائرة الحجز والتنفيذ ببريدة الشيخ عبدالله بن سليمان السحيمان، وتناول رئيس المحكمة العامة بالرس الشيخ خالد بن صالح الحجاج فقه التعامل مع قضايا الأحداث، فيما تناول رئيس المحكمة العامة بالبكيرية الشيخ عبدالله بن محمد الضالع إدارة المحكمة والمسؤوليات والاختصاصات، وتناول القاضي بالمحكمة العامة ببريدة الشيخ عبدالله بن عبدالرحمن الحميضي القضايا العقارية.</p>\r\n	<p>\r\n		كما تخلل البرنامج التدريبي للملازمين القضائيين إقامة ورشة عمل تقنية في النظام الشامل وآلية عمل التقنية في المحاكم.</p>\r\n	<p>\r\n		وتهدف الوزارة من تطبيق هذا البرامج والورش التدريبية إلى إكساب القضاة المزيد من المعرفة وتزويدهم بالمستندات الشرعية والإجراءات النظامية فيما يتعلق بالقدر المشترك بين القضاة وما يتعلق باختصاص كل فئة على حده والاستثمار في القضاة كخطوة أساسية في تطوير المحاكم بما يستجيب لحاجة الناس ودعم مواكبة التغيرات الاجتماعية والاقتصادية والتقنية في مجالات الحياة ورفع مستوى الإنتاجية وتحسينه من الناحيتين الكمية والنوعية والحد من الأخطاء والإقلال من الجهود المبذولة في الرقابة والإشراف على أداء العمل.</p>\r\n</div>\r\n<p>\r\n	 </p>\r\n', 2, '21.jpg', 'ACTIVE', '6-6-2014 11:07  صباحا', 'AR', '2016-07-02 21:59:59', NULL, NULL),
(11, '«العدل» تستقبل طلاب تقنية الحاسب الآلي لوظائفها التقنية', '<p style=\"text-align: justify;\">\r\n	الرياض - مبارك العكاش</p>\r\n<p style=\"text-align: justify;\">\r\n	استقبلت وزارة العدل الطلاب الخريجين في تخصص تقنية الحاسب الآلي والمشاركين في يوم المهنة الحادي والثلاثون المنعقد بجامعة الملك فهد للبترول والمعادن بالظهران ضمن مشاركتها البارزة في فعالياته.</p>\r\n<div id=\"article_text\">\r\n	<p style=\"text-align: justify;\">\r\n		وأوضحت الوزارة أنها مكنت خريجي تقنية الحاسب الآلي من تعبئة نموذج طلب التوظيف الإلكتروني الخاص بيوم المهنة على بوابتها الإلكترونية الخارجية حيث تسعى الوزارة لتوفير الوظائف ودعمها بالخريجين عن طريق التعاقد مع الشركة المشغلة لمشروع دعم وتشغيل التقنية الإلكترونية والحاسب الآلي بها وإشعارهم برسالة نصية بقبول طلبهم وإرسال السير الذاتية عبر البريد الخاص بيوم المهنة.</p>\r\n	<p style=\"text-align: justify;\">\r\n		ووفرت الوزارة عبر مشاركتها في يوم المهنة كافة المعلومات لتعريف الطلاب الخريجين وزوار المعرض بالخدمات الإلكترونية التي تقدمها والأعمال التي تقوم بها مؤكدة أن مشاركتها أتت من خلال حرصها وإيمانها بأهمية دعم العنصر البشري والكفاءات العلمية من خريجي الجامعات والمعاهد والكليات، وأكملت وزارة العدل بأنها حرصت على زيادة أعداد كوادرها الوطنية وتفعيل تلك الكوادر ومهاراتهم وفق أعلى معايير الجودة والتميز مما يكون له تأثيرا كبير في تحقيق أهدافها.</p>\r\n	<p style=\"text-align: justify;\">\r\n		يجدر الذكر أن وزارة العدل تسعى للمشاركة في كافة الأنشطة والفعاليات التي تخدم المواطن وتعرض من خلال تلك المشاركات العديد من الخدمات التعريفية بأنشطتها وأعمالها وفروعها وأقسامها كما تعمل على عرض وتوزيع المطبوعات التي تصدرها من أنظمة وتعليمات ونشرات تعريفية تفيد الجمهور بما يحتاجه عن الوزارة.</p>\r\n</div>\r\n<p>\r\n	 </p>\r\n', 2, '22.jpg', 'ACTIVE', '6-6-2014 11:10  صباحا', 'AR', '2016-07-02 21:59:59', NULL, NULL),
(12, 'وزارة العدل تنظم ست ورش عمل بابها والرياض.', '<div class=\"ExternalClass4FECAFB1766348D1AD59320645DCE343\" style=\"padding: 0px; margin: 0px;\">\r\n	<div style=\"padding: 0px; margin: 0px;\">\r\n		نظمت وزارة العدل ممثلة بالإدارة العامة لتدريب القضاة ست ورش عمل لأصحاب الفضيلة بابها والرياض .<br>\r\n		ففي مدينة ابها تناولت  ورشة عمل  (هيئات حقوق الإنسان) والتي قدمها عضو هيئة حقوق الإنسان الدكتور مفلح بن ربيعان القحطاني مفهوم حقوق الإنسان في الفقه الإسلامي والتصوير الغربي والميثاق العالمي لحقوق الإنسان في الشريعة ومواثيق واتفاقيات وحقوق الإنسان وحقوق الإنسان في المملكة العربية السعودية أو مؤسسات حقوق الإنسان في المملكة العربية السعودية والاعتبار القضائي لحقوق الإنسان .<br>\r\n		كما تناولت ورشة عمل ( غسيل الأموال) والتي قدمها عضو هيئة التدريس  كلية الملك فهد الأمنية الدكتور محمد بن علي القحطاني مخاطر وآثار غسل الأموال ودور الجهات الرقابية والإشرافية في مراقبة غسيل الأموال والجهود الدولية في مكافحة غسل الأموال وسلطة قاضي التقديرية في تحديد عقوبة غسيل الأموال , والأموال الناتجة عن غسيل الأموال لصالح دول أخرى والمحاكم المختصة بالفصل في جريمة غسيل الأموال .<br>\r\n		فيما تناولت ورشة عمل ( القراءة السريعة والتلخيص ) والتي قدمها المدرب اشرف غريب معدل سرعة القراءة والفرق بين التلخيص والاختصار ومهارات الحفظ والتذكر وتطبيق عملي على قراءة الصكوك ومحاضر التحقيق .<br>\r\n		وتناولت ورشة عمل ( القيادة الفعالة ) والتي قدمها المدرب محمد سلامة الزيود مقدمة في القيادة الفعالة ( ماهية القيادة والقائد والمرؤوس و القيادة ) وخصائص القادة الفعالين وأساليب القيادة والدعم الوظيفي وبناء فرق العمل وقيادة فريق من القادة وتحديد الأولويات واتخاذ القرار .</div>\r\n	<div style=\"padding: 0px; margin: 0px;\">\r\n		فيما تناولت ورشة عمل ( النظام الشامل وإستخداماته) والتي قدمها المدرب عبدالرحمن علي المعارك مفهوم التقنية وعمل القاضي والنظام الشامل ومجالات تطبيقاته والجوانب التخصصية في التعاملات الإلكترونية ( الإثبات والتعاملات الإلكترونية والهوية الإلكترونية والأدلة الإلكترونية  وصيغة العقد الإلكتروني وطرق الإثبات والتوثيق الإلكتروني والمعاملات المالية ومسائل الطلاق والزواج الإلكترونية.<br>\r\n		 كما تناولت ورشة عمل ( إدارة المكتب القضائي ) والتي قدمها فضيلة القاضي أحمد العميره أنواع المعاملات في المكتب القضائي وأعمال السكرتارية وأعمال الضبط وإدارة الوقت في المكتب القضائي وتنظيم الاجتماعات وتهيئتها ودور التقنية في فاعلية إدارة المكتب القضائي .<br>\r\n		وفي مدينة الرياض تناولت ورشة عمل ( الأوقاف وإجراءاتها ) والتي قدمها فضلية القاضي  بمحكمة عنيزة الشيخ ناصر عبدالله الجربوع خصائص الوقف وسماته وصلة الوقف بالقضاء والتأصيل الفقهي والنظامي وأنواع الوقف من حيث المستفيدين ومن حيث المال الموقف ومسائل وتطبيقات في الأوقاف وتحديات الأوقاف ودور القضاء في حلها وسبل استمرارها وتطور قسم الخبراء في المحكمة لتقدير وتثمين العقارات .<br>\r\n		وتهدف الوزارة من إقامة هذه الورش التدريبية إلى إكساب أصحاب الفضيلة المعرفة وتزيدهم بالمستندات الشرعية والإجراءات النظامية فيما يتعلق بالقدر المشترك بين القضاة وما يتعلق باختصاص كل فئة على حده والاستثمار في القضاة كخطوة أساسية في تطوير المحاكم بما يستجيب لحاجة الناس ودعم مواكبه التغيرات الاجتماعية والاقتصادية والتقنية في مجالات الحياة ورفع مستوى الانتاجية وتحسينه من الناحيتين الكمية والنوعية والحد من الأخطاء والإقلال من الجهود المبذولة في الرقابة والإشراف على أداء العمل .</div>\r\n</div>\r\n<p>\r\n	 </p>\r\n', 2, '9.jpg', 'ACTIVE', '3-9-2014 2:49  صباحا', 'AR', '2016-07-02 21:59:59', '2016-07-28 05:27:08', NULL),
(13, 'وزارة العمل تربط جولاتها التفتيشية الميدانية مع الوزارة بمركز عمليات تقني متقدم', '<p style=\"margin: 0px 0px 1.25em; padding: 0px; line-height: 24px; color: rgb(0, 0, 0); font-family: Tahoma; font-size: 14px; text-align: justify;\">\r\n	دشنت وزارة العمل اليوم مركز عمليات التفتيش، بهدف رفع كفاءة الزيارة التفتيشية ‏لمنسوبي الوزارة باستخدام الوسائل التقنية المتقدمة من خلال ربط العمل الميداني بقيادات التفتيش في الوزارة.</p>\r\n<p style=\"margin: 0px 0px 1.25em; padding: 0px; line-height: 24px; color: rgb(0, 0, 0); font-family: Tahoma; font-size: 14px; text-align: justify;\">\r\n	وأوضح نائب وزير العمل الدكتور مفرج الحقباني ‏أن مركز العمليات هو إدارة تقنية لأعمال التفتيش، من خلال تحديد نقاط التفتيش المجدولة، والشفافية في التأكد من تنفيذها، والمتابعة بهدف تقييم العمل، ومدى التزام العميل من خلال الزيارات التتابعية.</p>\r\n<p style=\"margin: 0px 0px 1.25em; padding: 0px; line-height: 24px; color: rgb(0, 0, 0); font-family: Tahoma; font-size: 14px; text-align: justify;\">\r\n	وأُنشئ المركز لتقديم الدعم للمفتشين في الميدان وتذليل ما يواجههم من صعوبات، ووضع الحلول المناسبة لها، وتزويد المفتشين بمعلومات موثقة من الأنظمة واللوائح والقرارات الرسمية.</p>\r\n<p style=\"margin: 0px 0px 1.25em; padding: 0px; line-height: 24px; color: rgb(0, 0, 0); font-family: Tahoma; font-size: 14px; text-align: justify;\">\r\n	وتم ربط مركز عمليات التفتيش بنظام دعم المركبات عبر الأقمار الاصطناعية، لربط جميع مركبات التفتيش بمركز العمليات، لتقديم المساندة لها في حالة تعرضها للأعطال أو السرقة.</p>\r\n<p style=\"margin: 0px 0px 1.25em; padding: 0px; line-height: 24px; color: rgb(0, 0, 0); font-family: Tahoma; font-size: 14px; text-align: justify;\">\r\n	ويحتوي مركز العمليات على برامج وتقنيات تسهل وتقدم الدعم المعلوماتي واللوجستي للمفتشين الميدانيين، بنظام \"أوتوماكس\" العالمي الذي يصمم برامج الزيارات، ويحدد مساراتها ويرصد نتائجها.</p>\r\n<p style=\"margin: 0px 0px 1.25em; padding: 0px; line-height: 24px; color: rgb(0, 0, 0); font-family: Tahoma; font-size: 14px; text-align: justify;\">\r\n	ويقدم النظام للمديرين والقيادات تقارير متابعة ميدانية لأعمال التفتيش والمفتشين بشكل لحظي، ويستقبل أسئلة واستفسارات المفتشين الميدانيين عبر 13 خطا تستقبل المكالمات في وقت واحد.</p>\r\n<p style=\"margin: 0px 0px 1.25em; padding: 0px; line-height: 24px; color: rgb(0, 0, 0); font-family: Tahoma; font-size: 14px; text-align: justify;\">\r\n	 </p>\r\n', 2, '9.jpg', 'ACTIVE', '3-9-2014 2:52  صباحا', 'AR', '2016-07-02 21:59:59', '2016-07-28 05:27:56', NULL),
(14, 'العدل لـ المحاكم اعتمدوا البيانات الشخصية إثباتا للمراجعين', '<p style=\"margin: 5px 0px 13px; padding: 0px; border: 0px; vertical-align: baseline;\">\r\n	طالبت وزارة العدل من جميع المحاكم وكتابات العدل بالاعتماد على قواعد البيانات الشخصية، في إثبات الهوية للمواطنين والمقيمين، عند إجراء أي معاملة تتعلق بهم.</p>\r\n<p style=\"margin: 5px 0px 13px; padding: 0px; border: 0px; vertical-align: baseline;\">\r\n	وجاءت تلك المطالبة بعد أشهر من تطبيق نظام إثبات الهوية، ودعت وزارة العدل لمخاطبة الجهات المعنية لطلب الحث في استمرار التنسيق فيما بينها للمسارعة باعتماد البصمة الإلكترونية تحقيقا لمزيد من الدقة.</p>\r\n<p style=\"margin: 5px 0px 13px; padding: 0px; border: 0px; vertical-align: baseline;\">\r\n	ومن جهته، أكد لـ”الوطن” مصدر مطلع، بأن وزير العدل رئيس المجلس الأعلى للقضاء محمد بن عبدالكريم العيسى، طالب كافة المحاكم وكتابات العدل بالاعتماد على قواعد البيانات الشخصية في إثبات الهوية للمواطنين والمقيمين، عند إجراء أي معاملة، والاعتماد أيضا على البطاقة الشخصية في إثبات هوية النساء لمن تحمل بطاقة شخصية خاصة بها في إجراء أي معاملة تتعلق بها، وباعتماد البصمة الإلكترونية لتحقيق مزيد من الدقة.</p>\r\n<p style=\"margin: 5px 0px 13px; padding: 0px; border: 0px; vertical-align: baseline;\">\r\n	وذكر المصدر بأن وزير العدل أشار إلى ضرورة التنسيق مع الجهات الحكومية المعنية، للمسارعة باعتماد البصمة الإلكترونية تحقيقا لمزيد من الدقة، منوها إلى أن التعاون بين وزارة الداخلية ووزارة العدل في هذا المجال انتهى إلى تمكين وزارة العدل من الاستفادة من قواعد البيانات الشخصية الخاصة بالمواطنين والمقيمين في المملكة، وقال المصدر: “إن وزارة العدل قامت بتجهيز الأنظمة والأجهزة التي يمكن من خلالها تفعيل الاستفادة من هذه البيانات، كما قامت بتوزيع الأجهزة المتعلقة بذلك على جميع الجهات العدلية في المملكة”.</p>\r\n<div>\r\n	 </div>\r\n<div style=\"margin: 10px; padding: 0px; border: 0px; vertical-align: baseline; clear: both;\">\r\n	 </div>\r\n', 2, '26.jpg', 'ACTIVE', '3-9-2014 2:57  صباحا', 'AR', '2016-07-02 21:59:59', '2016-07-28 05:28:09', NULL),
(15, ' التحقيق في صكوك مزورة بعشرات المليارات', '<p>\r\n	كشفت مصادر مطلعة بوزارة العدل السعودية عن أن التحقيق في صكوك مضروبة صدرت عن كتابات عدل تتجاوز قيمتها المالية عشرات المليارات من الريالات، ما زالت جارية لاستكمال إجراءات عدم صحة هذه الصكوك.</p>\r\n<div>\r\n	 </div>\r\n<div>\r\n	وأشارت إلى أن الوزارة تعمل على كشف جميع الصكوك المزوّرة ومحاربتها وتطبيق الأنظمة والتعليمات بكل دقّة وحزم حيال ذلك، وبيَّن المصدر أن الوزارة إنما تؤدي بهذا واجبها الشرعي والنظامي، وفقا لصحيفة \"المدينة\".</div>\r\n<div>\r\n	 </div>\r\n<div>\r\n	وأضافت أن الوزارة تهيب بمن لديه أي إشكال حول أي صك الرفع للوزارة عنه، وإذا كان مصحوبًا بمعلومات شبهة فساد من محسوبيات أو تسهيلات أو رشاوى أو غيرها من أي كائن من كان أن يتمَّ الرفعُ بها للجهات الرقابية، ولدى هذه الجهات صلاحيةُ الاطلاع على سجلات كتابات العدل ومباشرة مهامها، وللعلم فإن غالب ما يجري التحفظ عليه من الصكوك يعكس بكل أسى وأسف مستوى عبث عدد من ضعفاء النفوس بالمصلحة العامة وبحقوق المواطنين الخاصة، وأكثرها تتركز على إضافة مساحات شاسعة على مشمول الصك الأصلي، وعلى تزوير الصكوك وتزوير مساحاتها والحصول على صكوك لا رصيد لها، كما يعمد بعضهم إلى الإفراغ أكثر من مرة في وقت متقارب بعد الحصول على الصك المشبوه.</div>\r\n<div>\r\n	 </div>\r\n<div>\r\n	وأشارت المصادر إلى تحرير وزارة العدل لأراضٍ تعود ملكيتها للدولة وأخرى للمواطنين طالتها عمليات تزوير عبر صكوك مضروبة بعدد من مناطق المملكة.</div>\r\n<div>\r\n	 </div>\r\n<div>\r\n	 وأكدت أن الوزارة طالبت من القضاة وكتاب الضبط بكافة المحاكم وكتابات العدل وقف إجراءات نقل ملكيات أو إفراغات أي صكوك \"غير عادية\" أو يشتبه بتزويرها أو تحريفها، وكذلك الصكوك التي لا يوجد لها أصول بالمحاكم، وإحالتها فورًا للوزارة لدراسة وضعها، ومن ثم إحالتها للجهات المختصة للتحقيق مع أطرافها.</div>\r\n<div>\r\n	 </div>\r\n<div>\r\n	وأوضحت أن الوزارة شددت على أهمية تفعيل هذا الإجراء، واعتباره نظامًا ملزمًا للتعامل مع مختلف الصكوك المشبوهة، ووفقًا للمادة الخامسة عشرة من اللائحة التنفيذية لاختصاص كتاب العدل، والتي تنص على أنه يتوجب على كاتب العدل الرفع بأي مستندات أو صكوك ووثائق يظهر عليها شبهة التزوير أو التحريف أو التي تكون أصولها ملغاة، وتحرير محضر بالواقعة، يرفق به ما يثبت شخصية مقدم هذه الأوراق، تمهيدًا لإحالتها من قبل الوزارة للجهات المختصة.</div>\r\n<div>\r\n	 </div>\r\n<div>\r\n	وأوضحت أن الإجراءات التي تتخذها الوزارة في هذه القضايا تتمثل في شطب الصك المزور وإلغاء المساحات الأخرى التي أدخلت على الصك الأساسي بعد ثبوت أن المساحة المدخلة على الصك الأساسي تمت عبر التحايل والتزوير وصرف النظر عن الخصومة، وإعادة ملكية المساحة المدخلة على المخطط لأملاك الدولة، وتحويل أوراق القضية للجهات الأمنية لمحاسبة المتورطين في عملية التزوير والتحقيق معهم لمعرفة ملابسات إلحاق مساحات شاسعة بطرق مخالفة.</div>\r\n<div>\r\n	 </div>\r\n<div>\r\n	وأكد أن وزارة العدل تهدف من خلال التنظيمات التي وضعتها للتعامل مع صكوك الأراضي بالتشديد على إيقاف إجراءات نقل ملكيات وإفراغات أي صكوك \"غير عادية\"، أو يشتبه بتزويرها أو تحريفها وأن هذه الإجراءات تم تعميمها على كافة المحاكم حتى يتم إطلاع كتّاب العدل والقضاة عليها.</div>\r\n', 2, '27.jpg', 'ACTIVE', '3-9-2014 3:05  صباحا', 'AR', '2016-07-02 21:59:59', '2016-07-28 05:28:24', NULL),
(16, 'قرار المجلس اﻷعلى للقضاء بشأن قضايا السفر بالمحضون خارج البلاد، واعتبار ذلك من القضايا المستعجلة', '<p>\r\n	\"قرار لطيف\" قرار المجلس اﻷعلى للقضاء بشأن قضايا السفر بالمحضون خارج البلاد، واعتبار ذلك من القضايا المستعجلة </p>\r\n', 2, '29.jpg', 'ACTIVE', '22-9-2014 9:33  صباحا', 'AR', '2016-07-02 21:59:59', NULL, NULL);
