INSERT INTO `pages` (`id`, `title`, `detail`, `image`, `job_title`, `type`, `order`, `lang`, `vision`, `value`, `message`, `auther`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'عن المكتب', '<p style=\"transition-duration: 250ms; margin-bottom: 30px; padding: 5px 7.5px 0px 30px;\">تأسس مكتب عبد الله الفايز للمحاماة والتوثيق والتحكيم في 1429/06/06هـ بالرقم (33/29). ومنذ بدايته أصبح قبلة للأفراد والشركات وأصحاب الأعمال والمستثمرين، لما يقدمه من خدمات تلتزم أقصى معايير المهنية وتقوم على صدقية الاستشارة وحتمية حفظ أسرار العملاء.</p><p style=\"transition-duration: 250ms; margin-bottom: 30px; padding: 5px 7.5px 0px 30px;\">واليوم، بعد مضي أكثر من عشر سنوات على تأسيس المكتب، بات له موقع متقدم بين نظرائه في المملكة العربية السعودية وصار قبلة لطلاب الخدمات القانونية بشتى تصنيفاتهم وفي شتى المجالات.</p><p style=\"transition-duration: 250ms; margin-bottom: 30px; padding: 5px 7.5px 0px 30px;\">باختصار، مع الفائز.. أنت الفائز.</p><div class=\"clearfix\" style=\"box-sizing: border-box; outline: none; transition: all 250ms ease-in-out; color: rgb(127, 127, 127); font-family: CoHeadlineTrial-Regular, sans-serif; font-size: 16px; font-style: normal; font-variant: normal; font-weight: normal; letter-spacing: normal; line-height: 27.2px; orphans: auto; text-align: start; text-indent: 0px; text-transform: none; white-space: normal; widows: 1; word-spacing: 0px; -webkit-text-stroke-width: 0px;\"></div><div class=\"clearfix\" style=\"transition-duration: 250ms; color: rgb(127, 127, 127); font-family: CoHeadlineTrial-Regular, sans-serif; font-size: 16px; line-height: 27.2px;\"></div>', '', '', 'PAGE', 0, 'AR', '<p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">الريادة العالمية والتميز في تقديم الخدمات القانونية والمحاماة</span><br></p>', NULL, '<p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">الريادة والتميز في تقديم الخدمات القانونية في مجال المحاماة والاستشارات الشرعية والقانونية والتحكيم والتدريب القانوني، وتطوير الرعاية الحقوقية المبنية على الرؤية المتعمقة للأنظمة القضائية والبحث العلمي والتثقيف القانوني، وفقاً لمباديء المصداقية والثقة والالتزام المهني والدفاع عن الحق والعدل وشرف المهنة.</span></p>', NULL, '2016-07-08 05:15:36', '2019-02-17 11:04:51', NULL),
(2, 'أنظمة وقوانين الأعمال', '<p><span class=\"Apple-tab-span\" style=\"white-space: pre;\">	</span>يقدم مكتبنا خدماته القانونية إلى مجموعة من المنشآت المحلية والأجنبية ورجال الأعمال في إطار العناية الفردية القصوى لكل عملائنا لفهم وتلبية متطلباتهم بسرعة وفاعلية، وتزويدهم بالوسائل والنصائح القانونية الواضحة والعملية، وقد وضعنا نصب أعيننا أن نجتهد في خدمة عملائنا وتلبية احتياجاتهم بالعلم والمعرفة والثقة والقدرة على مواجهة التحديات؛ ومن ذلك:<br></p><p>- العقود والاتفاقيات والوثائق القانونية المتعلقة بالتجارة والأعمال.</p><p>- الاستثمار المحلي والأجنبي:</p><p><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>إننا ننظر بعناية إلى أهمية الاستثمارات في المملكة العربية السعودية ونقدم أقصى إمكانياتنا لخدمة حاجات عملائنا من المستثمرين القائمين أو المحتملين، حيث نزودهم بمعلومات كاملة ومفصّلة عن المناخ الاستثماري والتشريع القانوني في المملكة، ونعمل على إيجاد الإطار الأمثل والأكثر جدوى لدخول المستثمر إلى بيئة الأعمال في المملكة.</p><p><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>نقدم توصياتنا إلى المستثمرين بموضوعية وتجرّد، وبوصفنا جزءًا من المجتمع القانوني السعودي فإننا نضع في سلّم أولوياتنا متابعة أي تغييرات تشريعية محتملة يمكن أن تؤثر إيجاباً على عملائنا من المستثمرين.</p><p>- الوكالات التجارية والتوزيع.                            </p><p>- التجارة الدولية.</p><p>- حقوق وتراخيص الامتياز.</p><p>-الملكية الفكرية (حقوق النشر والعلامات التجارية وبراءات الاختراع):</p><p>    قوق الملكية الفكرية (من براءات الاختراع والعلامات التجارية وحقوق التأليف) أحد أصول المنشأة الأكثر أهميةً، والتي ينبغي حمايتها بغطاء قانوني مُحكم، وتعتبر خدماتنا في مجال حقوق الملكية الفكرية شاملة لجميع الإجراءات، بدءًا من إعداد وتقديم ومتابعة طلبات التسجيل داخل المملكة العربية السعودية وخارجها، وأيضاً المرافعة والتمثيل القضائي، وكذلك الدفاع في ادعاءات التعدي على ملكية براءات الاختراع أو حقوق النشر أو العلامات التجارية. نقدم أيضاً التوصيات القانونية لعملائنا حول الحقوق والمسؤوليات المرتبطة باستخدام حقوق الملكية الفكرية وممارسات المنافسة، وتقوم إستراتيجيتنا على بذل أقصى الجهود لحماية حقوق الملكية الفكرية مع تجنب اللجوء للقضاء قدر الإمكان.</p><p>-الملكية الصناعية.</p><p>-الأنظمة المالية وأسواق المال.</p><p>- الزكاة والنظام الضريبي:</p><p><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>على خلاف الأحكام الشرعية الثابتة المنظِّمة للزكاة والمستمدة من الشريعة الإسلامية، فإنَّ نظام الضريبة في المملكة العربية السعودية – المطبق على المنشآت والاستثمارات الأجنبية – قد خضع لإعادة هيكلة وبعض التغييرات مؤخراً، وهو ما يتوافق معه دورنا في تحليل المناخ الضريبي وتقديم النصح إلى عملائنا حول الالتزامات الضريبية المطبقة في المملكة، ويتضمن تحليلنا وتوصياتنا ما يخص التبعات الضريبية على مختلف التصرفات ومساعدة عملائنا على تنظيم شؤونهم الضريبية، علاوةً على ذلك فإننا نقوم بتمثيل عملائنا أمام مصلحة الزكاة والدخل.</p><p>- التأمين وإعادة التأمين.</p><p>-العمل والعمال والضمان الاجتماعي:</p><p><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>فاستناداً على المزاولة القانونية الطويلة لمكتبنا في خدمة مجموعة من كبار أصحاب العمل في المملكة العربية السعودية، فإننا مؤهلين لتقديم أنظمة العمل الداخلية والهياكل الخاصة بحقوق ومزايا الموظفين بما يتفق مع نظام العمل، كما تشمل خدماتنا التفاوض بين أصحاب العمل والمستخدمين وإعداد اتفاقيات التوظيف الجماعية والفردية ومتابعة إجراءات التقاضي وتسوية المنازعات العمالية.</p><p>-الملكية العقارية: </p><p><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>يمتلك مكتبنا خبرات عملية واسعة تغطي مختلف أنواع الصفقات والتصرفات العقارية؛ ويشمل ذلك التفاوض وصياغة عقود التملك، ترتيبات التمويل والسداد، عقود الإيجار، عقود المقاولات والإنشاءات، عقود الانتفاع، ومختلف أنواع المستندات القانونية الخاصة بالتصرفات العقارية التجارية أو السكنية. ومن جانبٍ آخر فإننا نقوم بالبحث</p><p><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>والتحليل للأوضاع القانونية للعقارات ورفع التوصيات اللازمة للوصول إلى المركز القانوني الأمثل، ويضاف لهذه الخدمات المقدَّمة منا في متابعة استخراج الصكوك وحجج الاستحكام.</p>', '1467463576.png', '', 'PAGE', 0, 'AR', NULL, NULL, NULL, NULL, '2016-07-02 09:21:44', '2016-07-11 17:34:51', NULL),
(3, 'الاختصاصات النوعية', '<p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">أ- الأحكام المتعلقة بالشركات والمؤسسات:</span><br></p><p><span class=\"Apple-tab-span\" style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica; white-space: pre;\">	</span><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">يقدم مكتب </span>عبدالله الفايز محامون وموثّقون ومحكّمون<span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"> حزمة متكاملة من الخدمات القانونية في مختلف مجالات نظام الشركات، بدءاً من التسجيل وهيكلة التنظيم إلى التصفية وشطب التسجيل، نقدم من بين خدماتنا الاستشارات القانونية بشأن الاندماج والاستحواذ وفصل وتقسيم الشركات، كما نعمل كمستشار قانوني عام للشركات لتنفيذ جميع احتياجاتها القانونية، بما في ذلك تمثيل العملاء لدى المراجع القضائية، وتحليل النتائج القانونية التي تترتب على الصفقات والتعاقدات التي ترغب الشركة في إبرامها وتقديم النصح بشأنها، وتولي الأمور القانونية المتعلقة بالتصرفات القانونية على العقارات. ومن ضمن هذه الخدمات:</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>1 -تأسيس وتسجيل الشركات والمؤسسات.</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>2- الاندماج والاستحواذ {التملك الكامل للشركات}.</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>3- المشاركة والائتلاف التضامني .</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>4- اتفاقيات المساهمات والحصص.</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>5- الإفلاس والتصفية.</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">ب- الاختصاصات المتعلقة بالشركات الحكومية:</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>1- عقود المناقصات والمشاريع الحكومية.</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>2- عقود بناء وإدارة واستثمار ونقل المشاريع.</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>3- تصديق وتوثيق الصكوك والمستندات.</span></p>', '1467463584.png', '', 'PAGE', 0, 'AR', NULL, NULL, NULL, NULL, '2016-07-02 09:22:21', '2016-07-27 04:39:32', NULL),
(4, 'تسوية المنازعات', '<p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">أ- المقاضاة والتحكيم:</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>يملك مكتبنا سجلاً حافلاً بالنجاحات في هذا المجال، فنحن نسعى بشكل مستمر ونكرِّس الكثير من الوقت والجهد للوصول إلى المفاهمات الودية والحلول وتسوية النزاعات بين عملائنا وخصومهم، لكننا بالمقابل نضطلع بدورنا بكل حزم ووعي وتصميم في متابعة القضايا لدى مختلف المحاكم والجهات الإدارية والقضائية في مختلف اختصاصات القانون، خلال إجراءات التقاضي وقبل بدئها نعمل بالتنسيق المتواصل مع عملائنا لوضع وتأسيس أفضل الاستراتيجيات اللازمة للادعاء أو الدفاع.</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>من ناحية أخرى فإنّ لدينا فريقاً تحكيميّاً متمكناً يضم مجموعة من المحكِّمين المتمرِّسين من ذوي النزاهة المهنية والاحتراف، ولهم تجربة شاملة كمستشارين ووسطاء ومحكِّمين في عدّة إجراءات تسوية منازعات.</p></span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">ب- الوساطة والمصالحة.</span><br></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">    في ضوء الطبيعة الخاصة لبعض النزاعات ومراعاتنا لاحتياجات العملاء فإننا نبذل ما بوسعنا لتوجيه أطراف النزاع نحو التفاوض،  وذلك بهدف تجنب إجراءات التقاضي الطويلة وتوفير وقت العميل وماله والحفاظ على علاقة تجارية مستقبلية طيبة مع خصومه بعد حل الخلاف، وفي هذا فإننا نقوم بتمثيل عملائنا أثناء المفاوضات ومناقشة مقترحات التسوية المقبولة لعملائنا، وبالتالي الوصول بالأطراف في معظم الحالات إلى المصالحة ومن ثَمَّ صياغة وتوثيق الاتفاق.</span><br></p>', '1467463592.png', '', 'PAGE', 0, 'AR', NULL, NULL, NULL, NULL, '2016-07-02 09:22:45', '2016-07-11 17:26:48', NULL),
(5, 'خدمات أُخرى ', '<p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">الخدمات القانونية والتقليدية العامة؛ وتشمل:</span><br></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">أ- شؤون الأحوال الشخصية وقضايا الشركات وغيرها.</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">ب- تحصيل الديون والذمم:</span></p><p><span class=\"Apple-tab-span\" style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica; white-space: pre;\">	</span><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">حيث يُعدّ تحصيل الديون في كثير من الحالات عملية مرهقة، وتستغرق وقتاً طويلاًِ يفضِّل الغالبية إحالتها إلى طرفٍ آخر للقيام بها. إنّ أحد عناصر الخدمات القانونية في مكتب </span>عبدالله الفايز محامون وموثّقون ومحكّمون<span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"> مساندة العملاء في عملية التحصيل من خلال تقديم حلول ناجحة لمشاكل التحصيل وسياسات الائتمان؛ كما نقوم بمتابعة تحصيل الديون والذمم من خلال المحاكم والسلطات الرسمية وبالاستفادة من جميع الإجراءات التي تكفلها المحاكم والأنظمة، بما فيها جميع خيارات التنفيذ على المدين.</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">ت- الدراسات والأبحاث القانونية:</span></p><p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\"><span class=\"Apple-tab-span\" style=\"white-space:pre\">	</span>وذلك من خلال استخدامنا الفعَّال لجميع مواردنا العلمية والبشرية يقوم مكتبنا بشكل مستمر بإِعداد بحوث وتحليلات ودراسات قانونية في المجالات التي تكون إمَّا موضع اهتمام عملائنا أو المستجدات القانونية في مختلف فروع القانون، وهو ما يثري خبراتنا العملية بالبحوث القانونية المنهجية المتقدمة، ويعزِّز من مكانة المقترحات والتوصيات القانونية التي نقدمها إلى عملائنا، والتي تخص بعض الحالات القانونية المعقّدة.</span></p>', '1467463566.png', '', 'PAGE', 0, 'AR', NULL, NULL, NULL, NULL, '2016-07-02 09:23:04', '2016-07-27 04:38:11', NULL),
