(14, 'عبدالله الفايز', '<address style=\"transition-duration: 250ms; line-height: 1.42857; color: rgb(3, 3, 3); font-family: tahoma, sans-serif; background-color: rgb(255, 255, 255);\"><span style=\"transition-duration: 250ms; text-align: right; font-family: tahoma, sans-serif !important;\">المحامي والموثق/ عبدالله بن عبدالرحمن بن إبراهيم الفايز، الممارس لمهنة المحاماة بموجب الترخيص الصادر من وزارة العدل برقم (29/33) وموجب ترخيص التوثيق رقم (00/00).</span></address>', '1557232207.jpg', 'المدير العام', 'PEOPLE', 0, 'AR', NULL, NULL, NULL, NULL, '2016-07-08 05:33:26', '2019-05-07 10:30:07', NULL),
(15, 'عمر العكرش', '<p><br></p>', '1557232192.jpg', 'محامي', 'PEOPLE', 0, 'AR', NULL, NULL, NULL, NULL, '2017-05-22 07:13:21', '2019-05-07 10:29:52', NULL),
(16, 'السيرة الذاتية', '<div><span style=\"font-weight: bold;\">المعلومات الشخصية:</span></div>\r\n<div>\r\n	<address><span style=\"text-align: right;\">المحامي والموثق/ عبدالله بن عبدالرحمن بن إبراهيم الفايز، الممارس لمهنة المحاماة بموجب الترخيص الصادر من وزارة العدل برقم (29/33) وموجب ترخيص التوثيق رقم (00/00).</span></address>\r\n	<address dir=\"RTL\">\r\n		<span style=\"font-weight: bold;\">المؤهلات:</span></address>\r\n	<p>\r\n		- بكالوريوس – كلية الشريعة – جامعة الإمام محمد بن سعود الإسلامية بالرياض.</p>\r\n	<p>\r\n		- ماجستير فقه مقارن من المعهد العالي للقضاء – جامعة الإمام محمد بن سعود الإسلامية بالرياض.</p>\r\n	<p>\r\n		- باحث لمرحلة الدكتوراه في الفقه المقارن من المعهد العالي للقضاء – جامعة الإمام محمد بن سعود الإسلامية بالرياض.</p>\r\n	<p>\r\n		- دبلوم محاماة – جامعة الإمام محمد بن سعود الإسلامية بالرياض.</p>\r\n	<p>\r\n		- عضو الجمعية العلمية القضائية.</p>\r\n	<p>    </p>\r\n	<address>\r\n		<span style=\"font-weight: bold;\">الخبرات العلمية:</span></address>\r\n	<p>\r\n		1. العمل في المحاماة والاستشارات القانونية والشرعية لدى مكتب عبدالعزيز القاسم محامون ومستشارون.</p>\r\n	<p>\r\n		2. العمل في المحاماة والاستشارات القانونية والشرعية لدى الإدارة القانونية في مجلس إدارة أعمال الشيخ صالح بن عبدالعزيز الراجحي.</p>\r\n	<p>\r\n		3. العمل في المحاماة والاستشارات القانونية والشرعية في مكتب المشورة محامون ومستشارون.</p>\r\n	<p>\r\n		4. العمل في حقل التربية والتعليم معلماً.</p>\r\n</div>\r\n<p>\r\n	 </p>\r\n', '', '', 'PAGE', 0, 'AR', NULL, NULL, NULL, NULL, '2016-07-11 18:01:27', '2018-04-19 05:05:24', NULL),
(17, 'نظام الملكية الفردية', '<p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">نظام الملكية الفردية</span><br></p>', '', '', 'SYSTEM', 0, 'AR', NULL, NULL, NULL, NULL, '2016-07-16 12:35:39', '2019-03-07 12:16:47', NULL),
(18, 'النظام الجديد للعمل والعمال', '<p><br></p>', '', '', 'SYSTEM', 0, 'AR', NULL, NULL, NULL, NULL, '2016-07-16 12:36:20', '2019-01-01 08:23:22', NULL),
(19, 'أهم مايحتاجه كتاب العدل والموثقون ومراجعيهم', '<p><br></p>', '', '', 'SYSTEM', 0, 'AR', NULL, NULL, NULL, NULL, '2016-07-16 12:36:45', '2019-01-01 08:24:25', NULL),
