(8, 'تحسين الأداء للتدريب', NULL, '8.jpg', NULL, 'http://tahseenalada.com/default.htm', 0, 'AR', '2016-07-02 22:32:40', '2016-07-31 06:14:04', '2016-07-31 06:14:04'),
(9, 'العجلان جلوبل', '<p style=\"margin-top: 15px; margin-bottom: 15px;\">مجموعة العجلان جلوبل هي مجموعة استثمارية سعودية تأسست في مدينة الرياض عاصمة المملكة العربية السعودية وأصبحت تمتلك العديد من الاستثمارات في مختلف المجالات وفي عدد من مناطق المملكة العربية السعودية وبعض دول العالم، واليوم تفخر المجموعة بوجود أكثر من ١٥٠٠ موظف هم نخبة من المهنيين من ذوي الإختصاصات المختلفة والخبرة العالية يعملون في شركاتها في مختلف المرافق والقطاعات الصناعية والخدمات المتنوعة للمجموعة معززة بتحالفات وشراكات استراتيجية.</p><div><br></div>', '1469951568.JPG', '', 'http://www.lawfayez.com/', 1, 'AR', '2016-07-31 04:52:48', '2017-05-22 07:35:29', NULL),
(10, 'المركز التشيكي للعلاج الطبيعي و التأهيلي', '<p>يعتبر المركز التشيكى للعلاج الطبيعي والتأهيلي الأول من نوعه في المملكة من حيث طريقة العلاج والمعدات المستخدمة بإتباع الأسلوب التشيكي في العلاج الطبيعي وهو من أفضل طرق العلاج الطبيعي في العالم.</p><div><br></div>', '1469951641.jpg', '', 'http://cz-center.com', 2, 'AR', '2016-07-31 04:54:01', '2017-05-22 07:37:16', NULL),
(11, 'الطاقة البيضاء', '<p style=\"border: 0px; margin-bottom: 0px; padding: 0px 0px 20px; vertical-align: baseline; background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;\">“الطاقــة البيضــاء” هــي شــركة اســتثمارية ســعودية متخصصــة فــي هندسة وتصميــم وتشغيل أنظمــة الطاقــة الشمســية والمتجــددة بأنواعها ولهــا العديــد مــن المصالــح والاستثمارات علــى الصعيديــن المحلــي والدولــي مــن خــلال منتجاتهــا المتطــورة وخدماتهــا الفريــدة وشــراكاتها الاستراتيجية فــي مجــال الطاقــة المتجــددة.</p><div><br></div>', '1469951721.jpg', '', 'http://www.white-energy.com.sa/', 5, 'AR', '2016-07-31 04:55:21', '2017-05-22 07:37:16', NULL),
(12, 'مركز الاستطلاع والقياس', '<div dir=\"rtl\" style=\"margin: 0px; padding: 0px; vertical-align: baseline; border: 0px; outline-width: 0px; background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;\"><span style=\"margin: 0px; padding: 0px; vertical-align: baseline; border: 0px; outline-width: 0px; background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;\">مركز الاستطلاع والقياس للدراسات هو مركز متخصص في القياس واستطلاعات الرأي العام، ويملك القدرة الكاملة على تلبية احتياجات المستفيدين من الاستطلاعات الدقيقة في العالم العربي بطريقة منهجية صارمة، تقوم على فحص البيئة والمعلومة، عبر فريق مدرب يعمل وفق نماذج محكّمة، مدعومة بخبرات متقدمة وبرامج الكترونية متطورة، بهدف دعم المسؤولين في الوزارات والهيئات والشركات بالمؤشرات الدقيقة التي تعينهم على التخطيط الناجح، وصناعة الاستراتيجيات الذكية، وتقديم المشورة المبنية على أساس واقعي.</span></div><div><strong style=\"margin: 0px; padding: 0px; vertical-align: baseline; border: 0px; outline-width: 0px; background: transparent;\"><span style=\"margin: 0px; padding: 0px; vertical-align: baseline; border: 0px; outline-width: 0px; font-size: 16px; background: transparent;\"><br></span></strong></div>', '1469951803.jpg', '', 'http://www.cpmo.com.sa/', 8, 'AR', '2016-07-31 04:56:43', '2017-05-22 07:37:16', NULL),
(13, 'ألفا', '<p><br></p>', '1469951984.jpg', '', 'http://www.lawfayez.com/', 14, 'AR', '2016-07-31 04:59:44', '2017-05-22 07:39:38', NULL),
(14, 'تحسين الأداء', '<p>مؤسسة تختص بتقديم الاستشارات التعليمية والإدارية، وبرامج التطوير الشخصي والمؤسسي، مع دعم مستمر من الوحدات المساندة في مجالات: التوظيف والتشغيل، والمتابعة، والإرشاد النفسي، والإشراف الأكاديمي، والموهبة والإبداع، ضمن أعلى معايير الجودة، وتقويم الأداء<br></p>', '1469952113.JPG', '', 'http://www.lawfayez.com', 10, 'AR', '2016-07-31 05:01:53', '2017-05-22 07:37:16', NULL),
(15, 'القارات للتدريب والتعليم', '<p>عتبر شركة القارات للتدريب والتعليم واحدة من اكبر شركات التدريب المعتمدة في المملكة وذلك من خلال خبرتها الطويلة و التي تمتد لثمانية عشر سنة في مجال التدريب والتعليم ذي الجودة العالية و تتميز الشركة بوجود كفاءات علمية متميزة من أساتذة الجامعات السعودية ونخبة من خبراء التدريب والمستشارين المعتمدين دوليا محليا والمتخصصين في مجالات تقنية المعلومات المختلفة والنواحي الإدارية و التطويرية<br></p>', '1469952201.jpg', '', 'http://www.qit.edu.sa/', 9, 'AR', '2016-07-31 05:03:21', '2017-05-22 07:37:16', NULL),
(16, 'هونج كونج', '<p><br></p>', '1469952244.jpg', '', 'http://www.lawfayez.com/', 11, 'AR', '2016-07-31 05:04:04', '2017-05-22 07:39:38', NULL),
(17, ' كبدة حجازي', '<p><br></p>', '1469952299.jpg', '', 'https://twitter.com/alhijazilivers', 18, 'AR', '2016-07-31 05:04:59', '2017-05-22 07:39:39', NULL),
