(13, 'Bin Towar & Co.', '<p>We work for a better future for coming generations.<br></p>', '1465544618.jpg', '#', NULL, 'ACTIVE', 'EN', '2016-06-10 12:43:38', '2016-06-10 12:43:38', NULL),
(14, 'Companies in a variety of fields', '<p><span style=\"font-family: beINNormal, Mj_SazehLight, tahoma, arial, helvetica;\">West Gulf Group of companies consists of companies in a variety of fields, which contributes and helps clients and customers to satisfy all their desires and their needs through group companies, and easier for them to communicate and coordinate. In addition to the long experience of the Governing Council of the Gulf market and country specifically.</span><br></p>', '1465544665.jpg', '#', NULL, 'ACTIVE', 'EN', '2016-06-10 12:44:25', '2016-06-10 12:44:25', NULL),
